import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.http.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import javax.servlet.http.HttpServletRequest;
import java.net.URI;
import java.net.URISyntaxException;
import java.time.Duration;
import java.util.concurrent.TimeUnit;

@SpringBootApplication
@RestController
@RequestMapping("/webhook")
public class WebhookHandler {

    @Autowired
    private RestTemplate restTemplate;

    @Value("${webhook.timeout.seconds:30}")
    private int timeoutSeconds;

    @Value("${webhook.allowed.hosts:}")
    private String[] allowedHosts;

    @PostMapping("/{partnerId}")
    public ResponseEntity<String> handleWebhook(
            @PathVariable String partnerId,
            @RequestBody String payload,
            HttpServletRequest request) {

        String sourceUrl = extractSourceUrl(request);
        if (sourceUrl == null || sourceUrl.isEmpty()) {
            return ResponseEntity.badRequest().body("Source URL not provided");
        }

        if (!isHostAllowed(sourceUrl)) {
            return ResponseEntity.status(HttpStatus.FORBIDDEN)
                    .body("Host not allowed");
        }

        try {
            String content = fetchContent(sourceUrl);
            return ResponseEntity.ok(content);
        } catch (Exception e) {
            return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR)
                    .body("Failed to fetch content: " + e.getMessage());
        }
    }

    private String extractSourceUrl(HttpServletRequest request) {
        String sourceUrl = request.getHeader("X-Source-Url");
        if (sourceUrl == null || sourceUrl.isEmpty()) {
            sourceUrl = request.getParameter("sourceUrl");
        }
        return sourceUrl;
    }

    private boolean isHostAllowed(String url) {
        if (allowedHosts == null || allowedHosts.length == 0) {
            return true;
        }

        try {
            URI uri = new URI(url);
            String host = uri.getHost();
            for (String allowedHost : allowedHosts) {
                if (host != null && host.equals(allowedHost)) {
                    return true;
                }
            }
        } catch (URISyntaxException e) {
            return false;
        }
        return false;
    }

    private String fetchContent(String url) throws RestClientException {
        HttpHeaders headers = new HttpHeaders();
        headers.setAccept(java.util.Arrays.asList(MediaType.APPLICATION_JSON));
        headers.set("User-Agent", "Webhook-Service/1.0");

        HttpEntity<String> entity = new HttpEntity<>(headers);

        restTemplate.getRestTemplate().setConnectTimeout(Duration.ofSeconds(timeoutSeconds));
        restTemplate.getRestTemplate().setReadTimeout(Duration.ofSeconds(timeoutSeconds));

        try {
            ResponseEntity<String> response = restTemplate.exchange(
                    url,
                    HttpMethod.GET,
                    entity,
                    String.class
            );
            return response.getBody();
        } catch (RestClientException e) {
            throw new RuntimeException("Failed to fetch content from " + url, e);
        }
    }

    @GetMapping("/health")
    public ResponseEntity<String> health() {
        return ResponseEntity.ok("Webhook service is running");
    }
}